#include <stdio.h>
#include <math.h>

typedef struct{float x,y,z;}V;
V A(V a,V b){return(V){a.x+b.x,a.y+b.y,a.z+b.z};}
V S(V a,V b){return(V){a.x-b.x,a.y-b.y,a.z-b.z};}
V M(V a,float t){return(V){a.x*t,a.y*t,a.z*t};}
float D(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}
V N(V a){float l=sqrtf(D(a,a));return M(a,1/l);}
float F(float x){return x<0?ceilf(x):floorf(x);}

int sphere(V o,V d,float*t,V*p,V*n){
 V c={0,-.5f,-5},oc=S(o,c);float r=1,b=2*D(oc,d),a=D(d,d),cc=D(oc,oc)-r*r,disc=b*b-4*a*cc;
 if(disc<0)return 0;
 float q=sqrt(disc),x=(-b-q)/(2*a);if(x<.001f){x=(-b+q)/(2*a);if(x<.001f)return 0;}
 *t=x;*p=A(o,M(d,x));*n=N(S(*p,c));return 1;
}
V sky(V d){float t=.5f*(d.y+1);return A(M((V){1,1,1},1-t),M((V){.5f,.7f,1},t));}
int shadow(V p,V l){float t;V q,n;return sphere(p,N(S(l,p)),&t,&q,&n);}
V trace(V o,V d){
 float ts,tp=(-1.5f-o.y)/d.y;V ps,ns,pp,np={0,1,0};int hs=sphere(o,d,&ts,&ps,&ns),hp=fabsf(d.y)>=.0001f&&tp>=.001f;
 if(!hs&&!hp)return sky(d);
 int sp=hs&&(!hp||ts<tp);V p=sp?ps:A(o,M(d,tp)),n=sp?ns:np,l={1,1,-1};
 if(shadow(p,l))return(V){.2f,.2f,.2f};
 float dif=fmax(0,D(n,N(S(l,p))))*.8f+.2f;
 if(sp)return(V){dif,dif*.2f,dif*.2f};
 float c=((int)(F(p.x)+F(p.z))&1)?.4f:.9f;return(V){c*dif,c*dif,c*dif};
}
int main(){
 int w=800,h=600;fprintf(stderr,"Creating high-resolution image: %dx%d\n",w,h);
 fwrite("This will be downsampled with ffmpeg after rendering\n",1,53,stderr);
 fwrite("Rendering high-resolution image...\n",1,35,stderr);
 FILE*f=fopen("image.ppm","w");V cam={0,0,0};
 fprintf(f,"P3\n%d %d\n255\n",w,h);
 for(int y=0;y<h;y++){
  fprintf(stderr,"\rProgress: %.1f%%",100.0f*y/h);
  float v=1-y/599.0f;
  for(int x=0;x<w;x++){
   float u=x/799.0f,px=(u*2.6666667f-1.3333334f),py=2*v-1;
   V col=trace(cam,N((V){px,py,-1}));
   int r=(int)(fmin(fmax(col.x,0),1)*255.99f),g=(int)(fmin(fmax(col.y,0),1)*255.99f),b=(int)(fmin(fmax(col.z,0),1)*255.99f);
   fprintf(f,"%d %d %d\n",r,g,b);
  }
 }
 fclose(f);fwrite("\nRendering complete\n",1,20,stderr);fprintf(stderr,"Wrote image to %s.\n","image.ppm");fwrite("Done.\n",1,6,stderr);
}

